+/// CircleCI connector state.
+#[derive(Debug)]
+pub struct CircleCiConnector {
+    base: BaseConnector,
+    config: Option<CircleCiConfig>,
+    client: Option<CircleCiClient>,
+    runtime: Option<ConnectorRuntime>,
+    started_at: Instant,
+    verifier: Option<CapabilityVerifier>,
+}
+
+impl CircleCiConnector {
+    /// Create a new connector instance.
+    #[must_use]
+    pub fn new() -> Self {
+        Self {
+            base: BaseConnector::new(ConnectorId::from_static("fcp.circleci")),
+            config: None,
+            client: None,
+            runtime: None,
+            started_at: Instant::now(),
+            verifier: None,
+        }
+    }
+
+    fn manifest_hash() -> String {
+        let mut hasher = Sha256::new();
+        hasher.update(MANIFEST_TOML.as_bytes());
+        format!("sha256:{}", hex::encode(hasher.finalize()))
+    }
+
+    /// Run connector diagnostics.
+    pub fn doctor(&self) -> DoctorResult {
+        let mut checks = Vec::new();
+
+        let configured = self.config.is_some();
+        checks.push(DoctorCheck {
+            name: "configuration".into(),
+            passed: configured,
+            message: Some(if configured {
+                "Configuration loaded".into()
+            } else {
+                "Not configured - run configure first".into()
+            }),
+            critical: true,
+        });
+
+        let client_ok = self.client.is_some();
+        checks.push(DoctorCheck {
+            name: "client_initialized".into(),
+            passed: client_ok,
+            message: Some(if client_ok {
+                "HTTP client initialized".into()
+            } else {
+                "HTTP client missing; re-run configure".into()
+            }),
+            critical: true,
+        });
+
+        let runtime_ok = self.runtime.is_some();
+        checks.push(DoctorCheck {
+            name: "runtime".into(),
+            passed: runtime_ok,
+            message: Some(if runtime_ok {
+                "ConnectorRuntime initialized".into()
+            } else {
+                "Runtime missing".into()
+            }),
+            critical: true,
+        });
+
+        if let Some(config) = &self.config {
+            let allowed_hosts = ["circleci.com"];
+            let host_part = config
+                .base_url
+                .split("://")
+                .nth(1)
+                .unwrap_or("")
+                .split('/')
+                .next()
+                .unwrap_or("")
+                .split(':')
+                .next()
+                .unwrap_or("");
+            let host_ok = host_part == "localhost"
+                || host_part == "127.0.0.1"
+                || allowed_hosts.contains(&host_part);
+            checks.push(DoctorCheck {
+                name: "network_constraints".into(),
+                passed: host_ok,
+                message: Some(if host_ok {
+                    "Base URL matches allowed host (circleci.com)".into()
+                } else {
+                    format!("Base URL {} does not match allowed hosts", config.base_url)
+                }),
+                critical: true,
+            });
+
+            let secretless = self.client.as_ref().is_some_and(|c| c.is_secretless());
+            checks.push(DoctorCheck {
+                name: "credential_mode".into(),
+                passed: !secretless,
+                message: Some(if secretless {
+                    "Credential injection required via egress proxy".into()
+                } else {
+                    "API token configured".into()
+                }),
+                critical: false,
+            });
+        }
+
+        DoctorResult::from_checks(checks)
+    }
+}
+
+impl Default for CircleCiConnector {
+    fn default() -> Self {
+        Self::new()
+    }
+}
