+            OP_PAGES_LIST | OP_PAGES_GET | OP_SEARCH => {
+                CapabilityId::from_static(CAP_PAGES_READ)
+            }
+            OP_PAGES_CREATE | OP_PAGES_UPDATE | OP_PAGES_DELETE => {
+                CapabilityId::from_static(CAP_PAGES_WRITE)
