+                    .input
+                    .get("limit")
+                    .and_then(|v| v.as_u64())
+                    .unwrap_or(25);
+                let resp = client
+                    .list_spaces(runtime, start, limit)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                serde_json::to_value(resp).map_err(|e| FcpError::Internal {
+                    message: format!("JSON serialization error: {e}"),
+                })?
+            }
+            OP_SPACES_GET => {
+                let space_key = req
+                    .input
+                    .get("space_key")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'space_key' field".into(),
+                    })?;
+                let resp = client
+                    .get_space(runtime, space_key)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                serde_json::to_value(resp).map_err(|e| FcpError::Internal {
+                    message: format!("JSON serialization error: {e}"),
+                })?
+            }
+            OP_PAGES_LIST => {
+                let space_key = req
+                    .input
+                    .get("space_key")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'space_key' field".into(),
+                    })?;
+                let start = req.input.get("start").and_then(|v| v.as_u64()).unwrap_or(0);
+                let limit = req
+                    .input
+                    .get("limit")
+                    .and_then(|v| v.as_u64())
+                    .unwrap_or(25);
+                let resp = client
+                    .list_pages(runtime, space_key, start, limit)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                serde_json::to_value(resp).map_err(|e| FcpError::Internal {
+                    message: format!("JSON serialization error: {e}"),
+                })?
+            }
+            OP_PAGES_GET => {
+                let page_id = req
+                    .input
+                    .get("page_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'page_id' field".into(),
+                    })?;
+                let resp = client
+                    .get_page(runtime, page_id)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
