+            OP_PAGES_CREATE => {
+                let space_key = req
+                    .input
+                    .get("space_key")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'space_key' field".into(),
+                    })?;
+                let title = req
+                    .input
+                    .get("title")
+                    .and_then(|v| v.as_str())
