+            OP_PAGES_UPDATE => {
+                let page_id = req
+                    .input
+                    .get("page_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'page_id' field".into(),
+                    })?;
+                let title = req
+                    .input
+                    .get("title")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'title' field".into(),
+                    })?;
+                let body_content = req
+                    .input
+                    .get("body")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'body' field".into(),
+                    })?;
+                let version_number = req
+                    .input
+                    .get("version_number")
+                    .and_then(|v| v.as_u64())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing or invalid 'version_number' field".into(),
+                    })?;
+                let version_message = req
+                    .input
+                    .get("version_message")
+                    .and_then(|v| v.as_str())
+                    .unwrap_or("");
+
+                let update_body = json!({
+                    "id": page_id,
+                    "type": "page",
+                    "title": title,
+                    "body": {
+                        "storage": {
+                            "value": body_content,
+                            "representation": "storage"
+                        }
+                    },
+                    "version": {
+                        "number": version_number + 1,
+                        "message": version_message
+                    }
+                });
+
+                let resp = client
+                    .update_page(runtime, page_id, &update_body)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                serde_json::to_value(resp).map_err(|e| FcpError::Internal {
+                    message: format!("JSON serialization error: {e}"),
+                })?
+            }
+            OP_PAGES_DELETE => {
+                let page_id = req
+                    .input
+                    .get("page_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'page_id' field".into(),
+                    })?;
+                client
+                    .delete_page(runtime, page_id)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                json!({ "deleted": true })
+            }
+            OP_SEARCH => {
+                let cql = req
+                    .input
+                    .get("cql")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'cql' field".into(),
+                    })?;
+                let start = req.input.get("start").and_then(|v| v.as_u64()).unwrap_or(0);
+                let limit = req
+                    .input
+                    .get("limit")
+                    .and_then(|v| v.as_u64())
+                    .unwrap_or(25);
+                let resp = client
+                    .search(runtime, cql, start, limit)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                serde_json::to_value(resp).map_err(|e| FcpError::Internal {
+                    message: format!("JSON serialization error: {e}"),
+                })?
+            }
+            OP_HEALTH => {
+                client.health_check().await.map_err(|e| e.to_fcp_error())?;
+                json!({ "status": "ok" })
+            }
+            _ => {
+                return Err(FcpError::InvalidRequest {
+                    code: 1004,
+                    message: format!("Unknown operation: {operation}"),
+                });
+            }
+        };
