+    #[test]
+    fn rate_limited_maps_to_fcp() {
+        let err = SquareError::RateLimited {
+            retry_after_ms: 3000,
+        };
+        let fcp_err = ConnectorErrorMapping::to_fcp_error(&err);
+        assert!(matches!(fcp_err, FcpError::RateLimited { .. }));
