+    #[test]
+    fn api_503_is_retryable() {
+        let err = SquareError::Api {
+            code: 503,
+            message: "Service unavailable".into(),
+        };
+        assert!(err.is_retryable());
+    }
+
+    #[test]
+    fn api_400_not_retryable() {
+        let err = SquareError::Api {
+            code: 400,
+            message: "Bad request".into(),
