+                    .post("https://zoom.us/oauth/token")
+                    .basic_auth(&client_id, Some(&client_secret))
+                    .header(CONTENT_TYPE, "application/x-www-form-urlencoded")
+                    .body(format!("grant_type=account_credentials&account_id={account_id}"))
+                    .send()
+                    .await;
